<a-modal class="w-2/5 sm:w-full" okType="default" :title="eventUser.id ? 'Edit user' : 'Add user'" :visible="true" centered :footer="null" @cancel="handleCloseModal"><event-user-form :eventUserFields="event.userFields" :eventUser="eventUser" :disableEmail="eventUser.id ? true : false" @set-event-user="handleSetEventUser"><a-form-item class="m-3 font-bold" label="Observations"><a-textarea v-model:value="eventUser.observations"></a-textarea></a-form-item><a-form-item class="font-bold m-3" v-if="eventUser.inscriptionTime" label="Inscription time"><a-tag>{{ eventUser.inscriptionTime }}</a-tag></a-form-item><a-form-item class="m-3 font-bold" label="Confirmed" html-for="confirmed_checkbox"><a-checkbox id="confirmed_checkbox" v-model:checked="confirmedCheck" @click="handleChangeCheckinTime"></a-checkbox></a-form-item><a-form-item class="m-3 font-bold" label="Emails marketing" html-for="emails_checkbox"><a-checkbox id="emails_checkbox" v-model:checked="emailsMarketingCheck" @change="handleChangeOptInMarketingEmails"></a-checkbox></a-form-item><error-save-user-message v-if="state.error" :errorCode="state.errorCode"></error-save-user-message><a-form-item><a-button class="absolute right-0" html-type="submit" :disabled="state.loading" type="primary">Save</a-button></a-form-item></event-user-form></a-modal>