<div class="bg-white"><table v-if="!eventUserFields.loading"><thead class="mt-5"><tr><th class="px-8 text-left sm:px-0">Field</th><th class="px-8 sm:px-2">Enabled</th><th class="px-8 sm:px-4">Required</th><th class="px-8 sm:px-4">Options</th></tr></thead><tbody><tr v-for="eventUserField in eventUserFields.data"><td class="text-left py-1 px-8 sm:px-0 sm:text-xs">{{eventUserField.fieldType.description}}</td><td class="py-1 px-14 sm:px-8"><a-checkbox v-model:checked="eventUserField.enabled" :disabled="eventUserField.disabled" @change="handleClickEnabled(eventUserField)"></a-checkbox></td><td class="py-2 px-14 sm:px-10"><a-checkbox v-model:checked="eventUserField.required" :disabled="eventUserField.disabled" @change="handleClickRequired(eventUserField)"></a-checkbox></td><td class="py-1 px-8 sm:px-0 sm:text-xs"><a-select v-if="eventUserField.fieldType.id === 1" v-model:value="treatmentOptions" style="width: 250px" mode="multiple" placeholder="Seleccione tratamiento" :options="defaultTreatmentOptions.map((option) =&gt; ({value: option}))" :disabled="!eventUserField.enabled" @change="handleAddTreatmentOption"></a-select></td></tr></tbody></table><br><div class="flex justify-end"><a-button :disabled="eventEditor.loading" @click="setUserFields" type="primary">Save</a-button></div></div>