<a-form class="m-0 w-full sm:w-full" v-if="state.form" ref="formRef" name="user" :model="state" :label-col="{ span: 5 }" layout="horizontal" labelAlign="left" @finish="onFinish" @finishFailed="validateEmail"><a-form-item class="m-3 font-bold" label="Treatment" v-if="treatmentField"><a-radio-group class="font-normal" v-model:value="state.eventUserTreatment" name="radioGroup" v-for="option in treatmentField.options"><a-radio :value="option">{{ option }}</a-radio></a-radio-group></a-form-item><a-form-item class="m-3 font-bold" v-for="(field, idx) in state.form" :key="field.key" :name="['form', idx, field.key]" :label="field.label" :rules="field.rules" :wrapper-col="{ span: field.width }"><a-input class="m-0" v-model:value="field[field.key]"></a-input></a-form-item><a-form-item class="m-3 font-bold" label="Email" v-if="disableEmail"><a-tag class="flex items-start h-8 m-0 mt-2 pl-3 leading-8 w-full text-[14px]" color="blue">{{eventUser.mail}}</a-tag></a-form-item><slot></slot></a-form>